import React from "react";
import ReactDOM from "react-dom/client";
import { RouterProvider, createRouter } from "@tanstack/react-router";
import { routeTree } from "./routeTree.gen"; // auto-generated by TanStack Router plugin

// Create the router from the AUTO-GENERATED route tree
// The plugin watches src/routes/ and regenerates this file on every save
const router = createRouter({ routeTree });

// TypeScript module augmentation — full type safety across the app
declare module "@tanstack/react-router" {
  interface Register {
    router: typeof router;
  }
}

ReactDOM.createRoot(document.getElementById("root")!).render(
  <React.StrictMode>
    <RouterProvider router={router} />
  </React.StrictMode>
);
